(window.webpackJsonp=window.webpackJsonp||[]).push([[907],{888:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> getMaximumGenerated = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n</span>) </span>{\\n    <span class=\\"hljs-keyword\\">if</span>(n===<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> arr=[<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">1</span>]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">2</span>;i&lt;=n;i++){\\n        <span class=\\"hljs-keyword\\">let</span> half=<span class=\\"hljs-built_in\\">Math</span>.floor(i/<span class=\\"hljs-number\\">2</span>)\\n        <span class=\\"hljs-keyword\\">if</span>(i%<span class=\\"hljs-number\\">2</span>===<span class=\\"hljs-number\\">0</span>){\\n            arr[i]=arr[half]\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n            arr[i]=arr[half]+arr[half+<span class=\\"hljs-number\\">1</span>]\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-built_in\\">Math</span>.max.apply(<span class=\\"hljs-built_in\\">Math</span>,arr)\\n};\\n</code></pre>\\n"],"titleSlug":"get-maximum-in-generated-array","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570 <code>n</code> \u3002\u6309\u4e0b\u8ff0\u89c4\u5219\u751f\u6210\u4e00\u4e2a\u957f\u5ea6\u4e3a <code>n + 1</code> \u7684\u6570\u7ec4 <code>nums</code> \uff1a</p>\\n\\n<ul>\\n\\t<li><code>nums[0] = 0</code></li>\\n\\t<li><code>nums[1] = 1</code></li>\\n\\t<li>\u5f53 <code>2 <= 2 * i <= n</code> \u65f6\uff0c<code>nums[2 * i] = nums[i]</code></li>\\n\\t<li>\u5f53 <code>2 <= 2 * i + 1 <= n</code> \u65f6\uff0c<code>nums[2 * i + 1] = nums[i] + nums[i + 1]</code></li>\\n</ul>\\n\\n<p>\u8fd4\u56de\u751f\u6210\u6570\u7ec4 <code>nums</code> \u4e2d\u7684 <strong>\u6700\u5927</strong> \u503c\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 7\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>\u6839\u636e\u89c4\u5219\uff1a\\n  nums[0] = 0\\n  nums[1] = 1\\n  nums[(1 * 2) = 2] = nums[1] = 1\\n  nums[(1 * 2) + 1 = 3] = nums[1] + nums[2] = 1 + 1 = 2\\n  nums[(2 * 2) = 4] = nums[2] = 1\\n  nums[(2 * 2) + 1 = 5] = nums[2] + nums[3] = 1 + 2 = 3\\n  nums[(3 * 2) = 6] = nums[3] = 2\\n  nums[(3 * 2) + 1 = 7] = nums[3] + nums[4] = 2 + 1 = 3\\n\u56e0\u6b64\uff0cnums = [0,1,1,2,1,3,2,3]\uff0c\u6700\u5927\u503c 3\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 2\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>\u6839\u636e\u89c4\u5219\uff0cnums[0]\u3001nums[1] \u548c nums[2] \u4e4b\u4e2d\u7684\u6700\u5927\u503c\u662f 1\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>n = 3\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n<strong>\u89e3\u91ca\uff1a</strong>\u6839\u636e\u89c4\u5219\uff0cnums[0]\u3001nums[1]\u3001nums[2] \u548c nums[3] \u4e4b\u4e2d\u7684\u6700\u5927\u503c\u662f 2\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>0 <= n <= 100</code></li>\\n</ul>\\n","title":"1646. \u83b7\u53d6\u751f\u6210\u6570\u7ec4\u4e2d\u7684\u6700\u5927\u503c","relatedTags":["\u6570\u7ec4"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1646"}')}}]);